from collections import deque

def minNumberOfFlips(mat):
    m, n = len(mat), len(mat[0])
    steps = 0
    dirs = [(0, 1), (0, -1), (1, 0), (-1, 0), (0, 0)]

    def encode(i, j):
        return i * n + j

    while True:
        flipped = 0
        que = deque()

        for i in range(m):
            for j in range(n):
                if mat[i][j] == 1:
                    que.append(encode(i, j))

        while que:
            cur = que.popleft()
            cur_i, cur_j = divmod(cur, n)

            for dx, dy in dirs:
                ni, nj = cur_i + dx, cur_j + dy
                if 0 <= ni < m and 0 <= nj < n:
                    mat[ni][nj] ^= 1
                    flipped += 1

        if flipped == 0:
            break
        steps += flipped

    for row in mat:
        if any(cell == 1 for cell in row):
            return -1

    return steps
```

    1. Initialize the step counter and the directions we need to flip.
2. Enter a loop that continues until no flipping is performed in one iteration (use a flipped counter to track flips).
3. For each 1 cell in the matrix, enqueue its encoded position `(i * n + j)` to ensure uniqueness in a queue.
4. Dequeue positions from the queue, and perform flip operations (XOR with 1) for the current cell and its neighbors.
5. Increment the step counter with the number of flipped cells in the current iteration.
6. After exiting the loop, if there are any remaining 1s in the matrix, return -1, as it's impossible to form a zero matrix. Otherwise, return the step counter.

