import java.util.*;

public int minNumberOfFlips(int[][] mat) {
    final int m = mat.length, n = mat[0].length;
    final int[][] dirs = {{0, 1}, {0, -1}, {1, 0}, {-1, 0}, {0, 0}};
    int steps = 0;

    while (true) {
        int flipped = 0;
        Queue<Integer> que = new LinkedList<>();

        for (int i = 0; i < m; ++i) {
            for (int j = 0; j < n; ++j) {
                if (mat[i][j] == 1) {
                    que.offer(i * n + j);
                }
            }
        }

        while (!que.isEmpty()) {
            int cur = que.poll(), cur_i = cur / n, cur_j = cur % n;
            for (int[] dir : dirs) {
                int ni = cur_i + dir[0], nj = cur_j + dir[1];
                if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                    mat[ni][nj] ^= 1;
                    ++flipped;
                }
            }
        }

        if (flipped == 0) {
            break;
        }
        steps += flipped;
    }

    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            if (mat[i][j] == 1) {
                return -1;
            }
        }
    }

    return steps;
}
